import { TickCategory } from '../../../../core/components/axes/types.js';
import { safeGet } from '../../../../core/utils/safe-get.js';
import {
  WeakMapCategory,
  CategoricalBarData,
} from '../../../types/categorical-bar-chart-data.js';

/**
 * get tick categories record id name
 * @param filteredCategories -
 *
 * @returns return Record key id, value name
 */
export const getTickCategories = (
  filteredCategories: CategoricalBarData[],
  categoryMap: WeakMapCategory,
): TickCategory => {
  const record: TickCategory = {};
  for (let i = 0; i < filteredCategories.length; i++) {
    const curr = safeGet(categoryMap, filteredCategories[i]);
    record[curr.id] = curr.name;
  }

  return record;
};
